export default function Detail() {
  return (
    <>
      <h3 className="tracking-tight text-balance text-gray-900 sm:text-7xl text-center">
        How does it work?
      </h3>
      <ol
        type="1"
        className="mt-8 text-pretty text-gray-500 sm:text-xl/8 lg:px-8"
      >
        <li>1. Register yourself here -&gt; Sign Up.</li>
        <li>2. Book a slot dedicatedly for your bike and let be in peace.</li>
      </ol>
    </>
  );
}
